/**
 * t is current time
 * b is start value
 * c is change in value
 * d is duration
 */

export const Cubic = {
  in(t: number, b: number, c: number, d: number) {
    const cc = c - b;
    t /= d;
    return cc * t * t * t + b;
  },
  out(t: number, b: number, c: number, d: number) {
    const cc = c - b;
    t /= d;
    t--;
    return cc * (t * t * t + 1) + b;
  },
  inOut(t: number, b: number, c: number, d: number) {
    const cc = c - b;
    t /= d / 2;
    if (t < 1) {
      return (cc / 2) * t * t * t + b;
    }
    return (cc / 2) * ((t -= 2) * t * t + 2) + b;
  },
};

export const Circ = {
  in(t: number, b: number, c: number, d: number) {
    const cc = c - b;
    t /= d;
    return -cc * (Math.sqrt(1 - t * t) - 1) + b;
  },
  out(t: number, b: number, c: number, d: number) {
    const cc = c - b;
    t /= d;
    t--;
    return cc * Math.sqrt(1 - t * t) + b;
  },
  inOut(t: number, b: number, c: number, d: number) {
    const cc = c - b;
    t /= d / 2;
    if (t < 1) {
      return (-cc / 2) * (Math.sqrt(1 - t * t) - 1) + b;
    }
    t -= 2;
    return (cc / 2) * (Math.sqrt(1 - t * t) + 1) + b;
  },
};
